class ErrorCategory(Enum):
    VALIDATION = "VALIDATION_ERROR"
    NOT_FOUND = "NOT_FOUND"
    INTERNAL = "INTERNAL_ERROR"
    DEPENDENCY = "DEPENDENCY_ERROR"
    TIMEOUT = "TIMEOUT_ERROR"
    PERMISSION = "PERMISSION_ERROR"
    RATE_LIMIT = "RATE_LIMIT_ERROR"


@dataclass
class DetailedError:
    """Structured error information for debugging."""
    error_id: str
    category: str
    message: str
    stack_trace: str
    method_name: str
    request_data: dict
    service_state: dict
    timestamp: str
    exception_type: str
    exception_args: list
    local_variables: dict
    suggestion: str = ""

    def to_json(self) -> str:
        return json.dumps(asdict(self), indent=2, default=str)


def capture_locals(frame_depth=2) -> dict:
    """Capture local variables from the calling frame for debugging."""
    try:
        frame = sys._getframe(frame_depth)
        local_vars = {}
        for key, value in frame.f_locals.items():
            if key.startswith('_') or key == 'self':
                continue
            try:
                serialized = repr(value)
                if len(serialized) > 500:
                    serialized = serialized[:500] + "...[truncated]"
                local_vars[key] = serialized
            except Exception:
                local_vars[key] = "<unserializable>"
        return local_vars
    except Exception:
        return {"capture_error": "Failed to capture local variables"}


def get_error_suggestion(exception: Exception) -> str:
    """Provide debugging suggestions based on exception type."""
    suggestions = {
        KeyError: "Check if the required key exists in the dictionary. Verify request data completeness.",
        ValueError: "Verify input data types and ranges. Check for None values or empty strings.",
        TypeError: "Check function argument types. Ensure proper type conversions.",
        ConnectionError: "Verify downstream service availability. Check network configuration.",
        TimeoutError: "Increase timeout settings or check downstream service performance.",
        PermissionError: "Verify service account permissions and access tokens.",
        FileNotFoundError: "Check file paths and ensure required files are deployed.",
        ZeroDivisionError: "Add zero-value checks before division operations.",
        AttributeError: "Verify object initialization and check for None references.",
        IndexError: "Add bounds checking for list/array access operations.",
    }
    for exc_type, suggestion in suggestions.items():
        if isinstance(exception, exc_type):
            return suggestion
    return "Review the stack trace and local variables for debugging clues."


def map_exception_to_grpc_code(exception: Exception, category: ErrorCategory) -> grpc.StatusCode:
    """Map exception/category to appropriate gRPC status code."""
    mapping = {
        ErrorCategory.VALIDATION: grpc.StatusCode.INVALID_ARGUMENT,
        ErrorCategory.NOT_FOUND: grpc.StatusCode.NOT_FOUND,
        ErrorCategory.INTERNAL: grpc.StatusCode.INTERNAL,
        ErrorCategory.DEPENDENCY: grpc.StatusCode.UNAVAILABLE,
        ErrorCategory.TIMEOUT: grpc.StatusCode.DEADLINE_EXCEEDED,
        ErrorCategory.PERMISSION: grpc.StatusCode.PERMISSION_DENIED,
        ErrorCategory.RATE_LIMIT: grpc.StatusCode.RESOURCE_EXHAUSTED,
    }
    return mapping.get(category, grpc.StatusCode.INTERNAL)


def grpc_error_handler(method_name: str):
    """Decorator for comprehensive gRPC error handling with detailed debugging info."""
    def decorator(func):
        @wraps(func)
        def wrapper(self, request, context):
            request_id = str(uuid.uuid4())
            start_time = time.time()

            # Track request in service state
            request_data = {}
            try:
                for field_desc in request.DESCRIPTOR.fields:
                    request_data[field_desc.name] = getattr(request, field_desc.name)
            except Exception:
                request_data = {"raw": str(request)}

            self.state.request_count += 1
            self.state.active_requests[request_id] = {
                "method": method_name,
                "start_time": datetime.utcnow().isoformat(),
                "request_data": request_data,
            }

            logger.info(
                f"[{request_id}] Starting {method_name} | "
                f"Request: {json.dumps(request_data, default=str)}"
            )

            try:
                result = func(self, request, context)
                elapsed = time.time() - start_time
                logger.info(f"[{request_id}] Completed {method_name} in {elapsed:.3f}s")
                return result

            except Exception as e:
                elapsed = time.time() - start_time
                self.state.error_count += 1
                self.state.last_error = str(e)
                self.state.last_error_time = datetime.utcnow().isoformat()

                # Determine error category
                category = self._categorize_exception(e)
                grpc_code = map_exception_to_grpc_code(e, category)

                # Capture comprehensive debugging info
                local_vars = capture_locals(frame_depth=2)

                detailed_error = DetailedError(
                    error_id=request_id,
                    category=category.value,
                    message=str(e),
                    stack_trace=traceback.format_exc(),
                    method_name=method_name,
                    request_data=request_data,
                    service_state=self.state.to_dict(),
                    timestamp=datetime.utcnow().isoformat(),
                    exception_type=type(e).__qualname__,
                    exception_args=[str(arg) for arg in e.args],
                    local_variables=local_vars,
                    suggestion=get_error_suggestion(e),
                )

                error_json = detailed_error.to_json()

                logger.error(
                    f"[{request_id}] Error in {method_name} after {elapsed:.3f}s | "
                    f"Category: {category.value} | "
                    f"Exception: {type(e).__name__}: {e}\n"
                    f"Full debug info:\n{error_json}"
                )

                # Set detailed error info on the gRPC context
                context.set_code(grpc_code)
                context.set_details(error_json)

                # Add trailing metadata with key debugging fields
                context.set_trailing_metadata([
                    ("x-error-id", request_id),
                    ("x-error-category", category.value),
                    ("x-error-type", type(e).__qualname__),
                    ("x-error-method", method_name),
                    ("x-error-timestamp", datetime.utcnow().isoformat()),
                    ("x-service-id", self.state.service_id),
                    ("x-request-count", str(self.state.request_count)),
                    ("x-error-count", str(self.state.error_count)),
                ])

                # Return empty/default response (client should check status code)
                return type(func.__annotations__.get('return', object))()

            finally:
                self.state.active_requests.pop(request_id, None)

        return wrapper
    return decorator


