class DebugServiceServicer(debug_service_pb2_grpc.DebugServiceServicer):
    """gRPC service with comprehensive error handling and debugging support."""

    def __init__(self):
        self.state = ServiceState()
        logger.info(f"Service initialized with ID: {self.state.service_id}")

    def _categorize_exception(self, exception: Exception) -> ErrorCategory:
        """Categorize an exception for proper gRPC status code mapping."""
        if isinstance(exception, (KeyError, ValueError, TypeError)):
            if isinstance(exception, KeyError):
                return ErrorCategory.NOT_FOUND
            return ErrorCategory.VALIDATION
        elif isinstance(exception, ConnectionError):
            return ErrorCategory.DEPENDENCY
        elif isinstance(exception, TimeoutError):
            return ErrorCategory.TIMEOUT
        elif isinstance(exception, PermissionError):
            return ErrorCategory.PERMISSION
        else:
            return ErrorCategory.INTERNAL

